// DESIGN SPEC — generated by Designer agent
// Coder: implement TODO items, do not change component structure or accessibility attributes
//
// WorkspaceSessionChip
// ────────────────────
// Project-level session switcher chip that lives in the top toolbar between
// the segmented tabs and the right-side global actions. Clicking the chip
// opens a glass popup listing the project's sessions; selecting a row emits
// the session id (the parent calls switchSession and routes accordingly).
//
// The component is presentational — popup open/close and outside-click
// handling are managed here so the page can drop it in with a single slot.
// The chip is keyboard-accessible: Enter / Space opens, Escape closes,
// arrow keys move the focused row inside the popup.

<template>
  <div class="session-chip" ref="rootRef">
    <button
      type="button"
      class="session-chip__trigger"
      :aria-haspopup="true"
      :aria-expanded="popupOpen"
      :aria-label="`切换项目会话 — 当前 ${currentLabel}`"
      @click="handleToggle"
      @keydown.down.prevent="openAndFocusFirst"
    >
      <span class="session-chip__icon" aria-hidden="true">
        <OiIcon name="chat-bubble" :size="14" />
      </span>
      <span class="session-chip__label ellipsis">{{ currentLabel }}</span>
      <span class="session-chip__caret" aria-hidden="true">
        <OiIcon name="chevron-down" :size="12" />
      </span>
    </button>

    <Transition name="session-chip-pop">
      <div
        v-if="popupOpen"
        class="session-chip__popup"
        role="dialog"
        :aria-label="'项目会话列表'"
        @keydown.down.prevent="focusRowOffset(1)"
        @keydown.up.prevent="focusRowOffset(-1)"
        @keydown.enter.prevent="commitFocusedRow"
        @keydown.esc.prevent="closePopup"
      >
        <header class="session-chip__popup-header">
          <h3 class="session-chip__popup-title">
            <span>会话流</span>
            <span class="session-chip__popup-title-caret" aria-hidden="true">
              <OiIcon name="chevron-down" :size="12" />
            </span>
          </h3>
          <p class="session-chip__popup-subtitle">{{ sessions.length }} 个会话 — 点击切换或创建新会话</p>
        </header>

        <ul v-if="sessions.length > 0" class="session-chip__list" role="listbox">
          <li
            v-for="(session, index) in sessions"
            :key="session.id"
            role="option"
            :aria-selected="session.active"
            class="session-chip__row"
            :class="{
              'session-chip__row--active': session.active,
              'session-chip__row--focus': focusedIndex === index,
            }"
            :ref="(el) => setRowRef(el as Element | null, index)"
            @click="handleSelect(session.id)"
            @mouseenter="focusedIndex = index"
          >
            <div class="session-chip__row-body">
              <div class="session-chip__row-title-row">
                <span class="session-chip__row-title ellipsis">{{ session.title }}</span>
                <span class="session-chip__row-time">{{ session.clockLabel }}</span>
              </div>
              <div v-if="session.preview" class="session-chip__row-preview ellipsis-2">
                {{ session.preview }}
              </div>
            </div>
            <span v-if="session.active" class="session-chip__row-check" aria-hidden="true">
              <OiIcon name="check" :size="14" />
            </span>
          </li>
        </ul>

        <div v-else class="session-chip__empty">
          <p>暂无会话 — 点击下方按钮创建第一个会话</p>
        </div>

        <footer class="session-chip__popup-footer">
          <button
            type="button"
            class="session-chip__create"
            :disabled="creating"
            @click="handleCreate"
          >
            <OiIcon name="plus" :size="14" />
            <span>{{ creating ? '创建中…' : '新建会话' }}</span>
          </button>
        </footer>
      </div>
    </Transition>
  </div>
</template>

<script setup lang="ts">
import { computed, nextTick, onBeforeUnmount, ref, watch } from 'vue'
import OiIcon from 'src/components/ui/OiIcon.vue'

// ── Public shape ─────────────────────────────────────────────────────────────

export interface SessionChipItem {
  id: string
  title: string
  preview: string
  timeLabel: string
  clockLabel: string
  meta: string
  active: boolean
}

// ── Props / emits ────────────────────────────────────────────────────────────

const props = withDefaults(defineProps<{
  sessions: SessionChipItem[]
  currentLabel?: string
  creating?: boolean
}>(), {
  currentLabel: '',
  creating: false,
})

const emit = defineEmits<{
  (e: 'select', id: string): void
  (e: 'create'): void
  (e: 'open'): void
  (e: 'close'): void
}>()

// ── Local state ──────────────────────────────────────────────────────────────

const popupOpen = ref(false)
const rootRef = ref<HTMLElement | null>(null)
const rowRefs = ref<HTMLElement[]>([])
const focusedIndex = ref(0)

const fallbackLabel = computed(() => '选择会话')
const currentLabel = computed(() => props.currentLabel || fallbackLabel.value)

function setRowRef(el: Element | null, index: number) {
  if (el instanceof HTMLElement) rowRefs.value[index] = el
  else rowRefs.value.splice(index, 1)
}

watch(popupOpen, (open) => {
  if (open) emit('open')
  else emit('close')
})

// ── Outside click / escape ───────────────────────────────────────────────────

function handleDocumentClick(event: MouseEvent): void {
  if (!popupOpen.value) return
  const root = rootRef.value
  if (!root) return
  if (event.target instanceof Node && !root.contains(event.target)) {
    closePopup()
  }
}

function handleDocumentKey(event: KeyboardEvent): void {
  if (!popupOpen.value) return
  if (event.key === 'Escape') {
    event.preventDefault()
    closePopup()
  }
}

onBeforeUnmount(() => {
  document.removeEventListener('mousedown', handleDocumentClick)
  document.removeEventListener('keydown', handleDocumentKey)
})

watch(popupOpen, (open) => {
  if (open) {
    document.addEventListener('mousedown', handleDocumentClick)
    document.addEventListener('keydown', handleDocumentKey)
    // Focus the active row by default
    const activeIndex = props.sessions.findIndex((s) => s.active)
    focusedIndex.value = activeIndex >= 0 ? activeIndex : 0
  } else {
    document.removeEventListener('mousedown', handleDocumentClick)
    document.removeEventListener('keydown', handleDocumentKey)
  }
})

// ── Handlers ─────────────────────────────────────────────────────────────────

function handleToggle(): void {
  popupOpen.value = !popupOpen.value
}

function openAndFocusFirst(): void {
  popupOpen.value = true
  void nextTick(() => focusRowIndex(0))
}

function closePopup(): void {
  popupOpen.value = false
}

function handleSelect(id: string): void {
  emit('select', id)
  closePopup()
}

function handleCreate(): void {
  emit('create')
}

function focusRowOffset(delta: number): void {
  if (props.sessions.length === 0) return
  const next = (focusedIndex.value + delta + props.sessions.length) % props.sessions.length
  focusedIndex.value = next
  focusRowIndex(next)
}

function focusRowIndex(index: number): void {
  const target = rowRefs.value[index]
  if (target) {
    void nextTick(() => target.focus())
  }
}

function commitFocusedRow(): void {
  const session = props.sessions[focusedIndex.value]
  if (session) {
    handleSelect(session.id)
  }
}
</script>

